// WalletServiceHandler is an implementation of the aes.wallet.v1.WalletService service.
type WalletServiceHandler interface {
	ListBillingAccounts(context.Context, *connect.Request[v1.ListBillingAccountsRequest]) (*connect.Response[v1.ListBillingAccountsResponse], error)
	GetBillingAccount(context.Context, *connect.Request[v1.GetBillingAccountRequest]) (*connect.Response[v1.GetBillingAccountResponse], error)
	GetWallet(context.Context, *connect.Request[v1.GetWalletRequest]) (*connect.Response[v1.GetWalletResponse], error)
	// GetWalletBalance returns the current prepay liability balance computed from
	// ledger_postings. Separate from GetWallet so the cheap balance-only lookup doesn't drag
	// the full wallet metadata + permissions check overhead. Caller needs wallet read access.
	GetWalletBalance(context.Context, *connect.Request[v1.GetWalletBalanceRequest]) (*connect.Response[v1.GetWalletBalanceResponse], error)
	// ListPublicMeterRates returns the currently-effective rate per (meter, currency). Read-only,
	// un-scoped — meters are public catalog data; pricing is the same for every customer (any
	// per-customer discounts will live in a separate negotiated_rates table later).
	ListPublicMeterRates(context.Context, *connect.Request[v1.ListPublicMeterRatesRequest]) (*connect.Response[v1.ListPublicMeterRatesResponse], error)
	// Payment method management. Metalhost never sees raw card data — the customer obtains a
	// Stripe payment method ID via Stripe.js client-side and posts the id here. Metalhost stores
	// (stripe_customer_id, stripe_payment_method_id, last4, brand, exp). AttachPaymentMethod
	// also creates the Stripe customer if the billing account doesn't have one yet.
	AttachPaymentMethod(context.Context, *connect.Request[v1.AttachPaymentMethodRequest]) (*connect.Response[v1.AttachPaymentMethodResponse], error)
	ListPaymentMethods(context.Context, *connect.Request[v1.ListPaymentMethodsRequest]) (*connect.Response[v1.ListPaymentMethodsResponse], error)
	DetachPaymentMethod(context.Context, *connect.Request[v1.DetachPaymentMethodRequest]) (*connect.Response[v1.DetachPaymentMethodResponse], error)
	SetDefaultPaymentMethod(context.Context, *connect.Request[v1.SetDefaultPaymentMethodRequest]) (*connect.Response[v1.SetDefaultPaymentMethodResponse], error)
	// Invoice viewer. Invoices are auto-generated by a monthly close worker (separate cron); these
	// RPCs let customers list/get/download. PDF lives in object storage; DownloadInvoicePDF
	// returns a signed URL.
	ListInvoices(context.Context, *connect.Request[v1.ListInvoicesRequest]) (*connect.Response[v1.ListInvoicesResponse], error)
	GetInvoice(context.Context, *connect.Request[v1.GetInvoiceRequest]) (*connect.Response[v1.GetInvoiceResponse], error)
	DownloadInvoicePDF(context.Context, *connect.Request[v1.DownloadInvoicePDFRequest]) (*connect.Response[v1.DownloadInvoicePDFResponse], error)
	// Auto-recharge — opt-in. Customer enables Stripe auto-charge by setting enabled=true with a
	// saved payment_method, threshold, and amount. The dispatcher only picks wallets where
	// enabled = TRUE; Metalhost never charges a card without explicit consent. Disable by setting
	// enabled=false (config is preserved so re-enabling doesn't require resubmitting threshold/amount).
	ConfigureAutoRecharge(context.Context, *connect.Request[v1.ConfigureAutoRechargeRequest]) (*connect.Response[v1.ConfigureAutoRechargeResponse], error)
	GetAutoRechargeConfig(context.Context, *connect.Request[v1.GetAutoRechargeConfigRequest]) (*connect.Response[v1.GetAutoRechargeConfigResponse], error)
	// GetCostForecast returns month-to-date spend + a linear projection to end-of-month. Customers
	// call this for budget tracking; the projection is naive (mtd_spend / days_elapsed × days_in_month)
	// with no seasonality or per-resource modeling.
	GetCostForecast(context.Context, *connect.Request[v1.GetCostForecastRequest]) (*connect.Response[v1.GetCostForecastResponse], error)
	// Wallet alerts. One config per wallet: balance_alert_minor (fire when prepay balance drops
	// below) and/or days_remaining_alert (fire when balance / daily burn falls below this many
	// days). Either can be unset (NULL) to disable that alert. Edge-fire arming — fires once
	// when the condition first becomes true, re-arms when balance recovers above the threshold.
	// Customer-side refunds are not modeled: open a support ticket; operator refunds via
	// Stripe Dashboard and the charge.refunded webhook posts the ledger entry.
	ConfigureWalletAlerts(context.Context, *connect.Request[v1.ConfigureWalletAlertsRequest]) (*connect.Response[v1.ConfigureWalletAlertsResponse], error)
	GetWalletAlerts(context.Context, *connect.Request[v1.GetWalletAlertsRequest]) (*connect.Response[v1.GetWalletAlertsResponse], error)
	// Customer-initiated top-ups (PLATFORM_DESIGN §6.11). Two flavors:
	//   - Stripe payment intent: customer's browser confirms a card charge; on success
	//     Metalhost's Stripe webhook posts a TOPUP_CLEARING / CUSTOMER_PREPAY_LIABILITY journal.
	//   - Coinbase checkout: returns a hosted Coinbase URL the customer pays USDC on (any chain
	//     Coinbase supports); the Coinbase webhook posts the same journal on payment success.
	CreateStripeTopUpIntent(context.Context, *connect.Request[v1.CreateStripeTopUpIntentRequest]) (*connect.Response[v1.CreateStripeTopUpIntentResponse], error)
	// CreateCardSetupIntent: Stripe SetupIntent in card mode. Returns the client_secret the
	// browser's <PaymentElement> needs to render + collect card details without charging.
	// After Stripe confirms, the frontend calls AttachPaymentMethod with the resulting
	// payment_method_id to persist + add to the customer. Used by onboarding + add-card UI.
	CreateCardSetupIntent(context.Context, *connect.Request[v1.CreateCardSetupIntentRequest]) (*connect.Response[v1.CreateCardSetupIntentResponse], error)
	// CreateCoinbaseTopUpCheckout: hosted USDC checkout for a wallet top-up. Returns a Coinbase
	// checkout URL the customer pays on; the /v1/public/coinbase/webhook handler credits the wallet.
	CreateCoinbaseTopUpCheckout(context.Context, *connect.Request[v1.CreateCoinbaseTopUpCheckoutRequest]) (*connect.Response[v1.CreateCoinbaseTopUpCheckoutResponse], error)
	ListTopUps(context.Context, *connect.Request[v1.ListTopUpsRequest]) (*connect.Response[v1.ListTopUpsResponse], error)
	GetTopUp(context.Context, *connect.Request[v1.GetTopUpRequest]) (*connect.Response[v1.GetTopUpResponse], error)
	// Usage query / export. QueryUsage aggregates usage_events by meter / project / time-bucket
	// and returns rows; ExportUsage materializes a CSV/NDJSON file in object storage and returns
	// a presigned URL (same pattern as AdminAuditService.ExportAuditEvents).
	QueryUsage(context.Context, *connect.Request[v1.QueryUsageRequest]) (*connect.Response[v1.QueryUsageResponse], error)
	ExportUsage(context.Context, *connect.Request[v1.ExportUsageRequest]) (*connect.Response[v1.ExportUsageResponse], error)
}

